css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
  height: 76px;
  aspect-ratio: 1;
  position: relative;
  --g:/calc(30.259% + 5.027px) calc(30.259% + 5.027px) radial-gradient(#0000 calc(70% - 8px),currentColor calc(71% - 8px) 70%,#0000 71%) no-repeat;
  mask: radial-gradient(100% 100%,#0000 calc((30.259% + 5.027px)/0.964 - 8.306px),currentColor calc((30.259% + 5.027px)/0.964 - 8.306px + 1px)) intersect,100% 50% var(--g),81.174% 89.092% var(--g),38.874% 98.746% var(--g),4.952% 71.694% var(--g),4.952% 28.306% var(--g),38.874% 1.254% var(--g),81.174% 10.908% var(--g);
  filter: blur(12px);
}.loader:before {content: "";
  position: absolute;
  inset: 0;
  background: conic-gradient(#0000 35%,var(--loader-color, #4f46e5),#0000 65%);
  animation: l9 2s linear infinite;
}@keyframes l9 {to {rotate: 1turn}}
